import { useEffect, useState } from "react";
import api from "../api";
import { useAuth, hasRole } from "../AuthContext";

export default function Dashboard() {
    const { user } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAcc   = hasRole(user, "ACCOUNTANT");

    const [summary, setSummary] = useState({ customers: 0, contracts: 0, paid: 0, remaining: 0 });
    const [recentContracts, setRecentContracts] = useState([]);
    const [upcomingEvents, setUpcomingEvents] = useState([]);

    useEffect(() => {
        // các API cũ của bạn, giữ nguyên
        (async () => {
            const s = await api.get("/api/dashboard/summary");   // giả định endpoint cũ
            setSummary(s.data || {});
            const rc = await api.get("/api/dashboard/recent-contracts");
            setRecentContracts(rc.data || []);
            // chỉ tải events nếu không phải accountant
            if (isAdmin || isSales) {
                const ev = await api.get("/api/events/me?nextDays=30");
                setUpcomingEvents(ev.data || []);
            }
        })();
    }, [isAdmin, isSales]);

    return (
        <div className="p-6 space-y-6">
            {/* Hàng thẻ số liệu */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {/* Khách hàng: ẨN với ACCOUNTANT */}
                {(isAdmin || isSales) && (
                    <Card title="Khách hàng" value={summary.customers} />
                )}

                <Card title="Hợp đồng" value={summary.contracts} />
                <Card title="Đã thu" value={(summary.paid||0).toLocaleString("vi-VN") + " đ"} />
                <Card title="Còn lại" value={(summary.remaining||0).toLocaleString("vi-VN") + " đ"} />
            </div>

            {/* Hợp đồng gần đây + Sự kiện sắp tới */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
                <RecentContracts data={recentContracts} className="lg:col-span-2" />

                {/* Sự kiện: ẨN hoàn toàn với ACCOUNTANT */}
                {(isAdmin || isSales) && (
                    <UpcomingEvents data={upcomingEvents} />
                )}
            </div>
        </div>
    );
}

/* --- Các component con tối giản (giữ nguyên của bạn nếu đã có) --- */
function Card({ title, value }) {
    return (
        <div className="p-5 bg-white rounded-2xl shadow border border-indigo-100">
            <div className="text-slate-500 text-sm">{title}</div>
            <div className="text-2xl font-semibold mt-2">{value}</div>
        </div>
    );
}

function RecentContracts({ data, className="" }) {
    return (
        <div className={"p-5 bg-white rounded-2xl shadow border border-indigo-100 " + className}>
            <div className="flex items-center justify-between mb-3">
                <div className="font-semibold">Hợp đồng gần đây</div>
            </div>
            {/* bảng hiển thị như hiện tại của bạn */}
            {/* ... giữ nguyên phần map danh sách ... */}
        </div>
    );
}

function UpcomingEvents({ data }) {
    return (
        <div className="p-5 bg-white rounded-2xl shadow border border-indigo-100">
            <div className="flex items-center justify-between mb-3">
                <div className="font-semibold">Sự kiện sắp tới</div>
            </div>
            {/* render events; nếu rỗng thì hiện “Không có sự kiện …” */}
            {/* ... giữ nguyên code cũ của bạn ... */}
        </div>
    );
}
